// Wikipedia-Suche + Zusammenfassung (REST-API, kein Schluessel).
async function run(input) {
  const q = String((input && input.query) || '').trim();
  if (!q) return { fehler: 'Bitte einen Suchbegriff angeben.' };
  const lang = String((input && input.lang) || 'de').toLowerCase().replace(/[^a-z]/g, '') || 'de';
  const sr = await fetch('https://' + lang + '.wikipedia.org/w/api.php?action=query&list=search&srlimit=1&format=json&origin=*&srsearch=' + encodeURIComponent(q));
  if (!sr.ok) return { fehler: 'Wikipedia-Suche fehlgeschlagen.' };
  const sd = await sr.json();
  const hit = sd.query && sd.query.search && sd.query.search[0];
  if (!hit) return { fehler: 'Kein Wikipedia-Artikel gefunden.', anfrage: q };
  const title = hit.title;
  const su = await fetch('https://' + lang + '.wikipedia.org/api/rest_v1/page/summary/' + encodeURIComponent(title));
  if (!su.ok) return { titel: title, zusammenfassung: '', url: 'https://' + lang + '.wikipedia.org/wiki/' + encodeURIComponent(title) };
  const d = await su.json();
  return { titel: d.title || title, zusammenfassung: d.extract || '', url: (d.content_urls && d.content_urls.desktop && d.content_urls.desktop.page) || '' };
}
